using System;
using System.DirectoryServices;

public class ActiveDirectoryAuthenticator
{
    public bool AuthenticateUser(string username, string password)
    {
        // Construct an LDAP query to find the user
        var searcher = new DirectorySearcher();
        searcher.Filter = $"(&(objectClass=user)(sAMAccountName={username}))";

        // Search for the user in Active Directory
        var results = searcher.FindAll();

        // Check if the user was found
        if (results.Count == 0)
        {
            return false;
        }

        // Get the first result and check its password
        var result = results[0];
        var userPrincipal = new UserPrincipal(result);
        var authResult = userPrincipal.ValidatePassword(password);

        // Return true if the authentication was successful, false otherwise
        return authResult;
    }
}